return items.map(item => {
    const data = item.json;
    let content = "";

    if (data.Question && data.Answer) {
        // FAQ
        content = `${data.Question}\n${data.Answer}`;
    } else if (data['Product Name'] && data.Description) {
        // Product
        content = `Product\nCategory: ${data.Category || "General"}\nName: ${data['Product Name']}\nDescription: ${data.Description}\nSize: ${data.Size || "N/A"}\nPrice: ${data.Price || "N/A"}`;
    } else {
        // Fallback
        content = `Other Data\n${JSON.stringify(data)}`;
    }

    return {
        json: {
            values: [],        // embedding node will fill this
            content: content   // EVERYTHING is now vectorized
        }
    };
});
